import{_ as t,o as i,c as h,ag as a}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"[Admin Specs] Sprint 4: Quản trị Đơn hàng (Order Management)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-4-dat-cho-thanh-toan/05-admin-specs.md","filePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-4-dat-cho-thanh-toan/05-admin-specs.md"}'),o={name:"99-tham-khao/archive/02-quan-ly-sprint/sprint-4-dat-cho-thanh-toan/05-admin-specs.md"};function r(e,n,l,s,g,c){return i(),h("div",null,[...n[0]||(n[0]=[a('<h1 id="admin-specs-sprint-4-quan-tri-đon-hang-order-management" tabindex="-1">[Admin Specs] Sprint 4: Quản trị Đơn hàng (Order Management) <a class="header-anchor" href="#admin-specs-sprint-4-quan-tri-đon-hang-order-management" aria-label="Permalink to &quot;[Admin Specs] Sprint 4: Quản trị Đơn hàng (Order Management)&quot;">​</a></h1><p>Đặc tả chi tiết giao diện Admin dành cho việc quản lý các giao dịch đặt chỗ và thanh toán.</p><h2 id="_1-man-hinh-dashboard-đon-hang-order-list" tabindex="-1">1. Màn hình Dashboard Đơn hàng (Order List) <a class="header-anchor" href="#_1-man-hinh-dashboard-đon-hang-order-list" aria-label="Permalink to &quot;1. Màn hình Dashboard Đơn hàng (Order List)&quot;">​</a></h2><ul><li><strong>Component</strong>: <code>Table</code> với bộ lọc trạng thái (Status Filter Tabs).</li><li><strong>Tabs Trạng thái</strong>: [Tất cả] [Chờ thanh toán] [Đã thanh toán] [Đã xác nhận] [Đã hủy] [Đã hoàn tiền].</li><li><strong>Columns</strong>: <ul><li><strong>Mã đơn</strong>: BK_123 (Có link click sang chi tiết).</li><li><strong>Tên Tour</strong>: &quot;Vịnh Hạ Long 2 ngày 1 đêm&quot;.</li><li><strong>Khách hàng</strong>: Tên + SĐT.</li><li><strong>Tổng tiền</strong>: Định dạng VNĐ (e.g. 1.200.000 VNĐ).</li><li><strong>Ngày đặt</strong>: 15:30 20/03/2026.</li><li><strong>Trạng thái</strong>: Chip màu tương ứng (e.g. PAID: Green, PENDING: Yellow).</li></ul></li></ul><h2 id="_2-trang-chi-tiet-đon-hang-order-details" tabindex="-1">2. Trang Chi tiết Đơn hàng (Order Details) <a class="header-anchor" href="#_2-trang-chi-tiet-đon-hang-order-details" aria-label="Permalink to &quot;2. Trang Chi tiết Đơn hàng (Order Details)&quot;">​</a></h2><ul><li><strong>Component</strong>: <code>Card</code> layout chia 3 phần.</li><li><strong>Phần 1: Thông tin Tour</strong>: Ngày khởi hành, người tham gia (Adult/Child).</li><li><strong>Phần 2: Thông tin Thanh toán</strong>: Phương thức (VNPay), Mã giao dịch cổng (Transaction ID).</li><li><strong>Phần 3: Lịch sử Trạng thái (Timeline)</strong>: Hiển thị dòng thời gian đơn hàng từ lúc đặt đến lúc hoàn thành.</li><li><strong>Hành động Admin</strong>: <ul><li>Nút &quot;Xác nhận giữ chỗ&quot; (Dành cho thanh toán chuyển khoản).</li><li>Nút &quot;Hủy đơn &amp; Hoàn tiền&quot; (Hủy đơn và gọi API hoàn tiền sang cổng).</li></ul></li></ul><h2 id="_3-quan-ly-slot-lich-khoi-hanh-inventory" tabindex="-1">3. Quản lý Slot &amp; Lịch khởi hành (Inventory) <a class="header-anchor" href="#_3-quan-ly-slot-lich-khoi-hanh-inventory" aria-label="Permalink to &quot;3. Quản lý Slot &amp; Lịch khởi hành (Inventory)&quot;">​</a></h2><ul><li><strong>Component</strong>: <code>Calendar View</code>.</li><li><strong>Mục tiêu</strong>: Admin thiết lập số lượng slot tối đa cho mỗi ngày của từng Tour.</li><li><strong>Cảnh báo</strong>: Hiển thị tooltip đỏ khi số lượng slot trống sắp hết.</li></ul><h2 id="_4-đac-ta-quy-trinh-admin-flows" tabindex="-1">4. Đặc tả Quy trình (Admin Flows) <a class="header-anchor" href="#_4-đac-ta-quy-trinh-admin-flows" aria-label="Permalink to &quot;4. Đặc tả Quy trình (Admin Flows)&quot;">​</a></h2><ul><li><strong>Exporting</strong>: Xuất danh sách khách hàng tham gia tour theo ngày (File Excel) để cung cấp cho hướng dẫn viên.</li><li><strong>Refund Logic</strong>: Khi Admin Refund, hệ thống phải cập nhật <code>Inventory</code> (Nhả slot) và cập nhật trạng thái đơn hàng.</li></ul><hr><p><em>Tài liệu đặc tả Admin cho Sprint 4.</em></p>',12)])])}const m=t(o,[["render",r]]);export{u as __pageData,m as default};
